// // This module synchronously captures the input data A on the falling edge of the clock signal Clk and outputs the stored value in Z.
module top_module(
    input [width-1:0] A,
    input Clk,
    output reg [width-1:0] Z
    );parameter width = 8;
    always @(posedge Clk)
    begin
        Z <= A;
    end
endmodule
